/**
 * Find the next high tide in a tide table at or after a given time.
 *
 * @param {Array<{time: string, type: string, height: number}>} tides
 *   Tide table entries with ISO 8601 time strings, a type of "high" or "low", and a height in metres.
 * @param {string} after ISO 8601 timestamp; entries with a time strictly after this value are considered.
 * @returns {{time: string, type: string, height: number}} The next high tide entry.
 * @throws {Error} When the table contains no high tide strictly after the given time.
 * @planks("I ask for the next high tide after {string}")
 */
function nextHighTide(tides, after) {
  const next = tides.find((t) => new Date(t.time) > new Date(after) && t.type === "high");
  if (!next) throw new Error("no upcoming high tide in data");
  return next;
}

module.exports = { nextHighTide };

